**Add the `updateProxyEnv` method (new function, add after `updateDefaultCAPackageVolume`):**

```go
// updateProxyEnv sets HTTP_PROXY, HTTPS_PROXY, and NO_PROXY environment variables
// on the trust-manager container from the cluster-wide Proxy config. When the
// Proxy API is not available (e.g. MicroShift), this is a no-op.
func (r *Reconciler) updateProxyEnv(deployment *appsv1.Deployment) {
	if !r.proxyInformer.Applicable() {
		return
	}

	proxyConfig, err := (*r.proxyInformer.InformerFactory).Config().V1().Proxies().Lister().Get("cluster")
	if err != nil {
		r.log.V(2).Info("failed to get cluster proxy config, skipping proxy env vars", "error", err)
		return
	}

	var envVars []corev1.EnvVar
	if proxyConfig.Status.HTTPProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "HTTP_PROXY", Value: proxyConfig.Status.HTTPProxy})
	}
	if proxyConfig.Status.HTTPSProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "HTTPS_PROXY", Value: proxyConfig.Status.HTTPSProxy})
	}
	if proxyConfig.Status.NoProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "NO_PROXY", Value: proxyConfig.Status.NoProxy})
	}

	if len(envVars) == 0 {
		return
	}

	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			existing := make(map[string]int, len(container.Env))
			for j, e := range container.Env {
				existing[e.Name] = j
			}
			for _, ev := range envVars {
				if j, ok := existing[ev.Name]; ok {
					deployment.Spec.Template.Spec.Containers[i].Env[j] = ev
				} else {
					deployment.Spec.Template.Spec.Containers[i].Env = append(deployment.Spec.Template.Spec.Containers[i].Env, ev)
				}
			}
			break
		}
	}
}
